// ============================================================
// ⚙️ Construire requêtes — version sous-workflow (1 jeune)
// Lit DIRECTEMENT depuis les noeuds précédents avec refs absolues
// ============================================================

// 1. Lire le profil jeune (depuis le noeud Postgres)
const profilResults = $('📋 Charger profil').all();
const j = profilResults.length > 0 ? profilResults[0].json : {};

// DEBUG : vérifier qu'on a bien le profil
if (!j.airtable_id) {
  return [{
    json: {
      jeune: { skills_inferees: '', frein_langue: false },
      romes_originaux: [],
      romes_elargis: [],
      nb_romes_originaux: 0,
      nb_romes_elargis: 0,
      elargissement_actif: false,
      token: '',
      ft_url: '',
      lba_url: '',
      debug_error: 'Profil jeune non trouvé dans Charger profil. profilResults.length=' + profilResults.length
    }
  }];
}

// 2. Token
const token = $('🔐 Token France Travail').first().json.access_token;

// 3. Passerelles ROME
const passerellesRaw = $('📋 Charger passerelles').all();
const passerellesMap = {};
for (const p of passerellesRaw) {
  const src = (p.json.rome_source || '').trim();
  const cible = (p.json.rome_cible || '').trim();
  const type = (p.json.type || '').trim().toLowerCase();
  if (!src || !cible) continue;
  if (type !== 'proche' && type !== 'evolution') continue;
  if (!passerellesMap[src]) passerellesMap[src] = [];
  passerellesMap[src].push(cible);
}

// 4. Parser les ROME
const romesOriginaux = (j.codes_rome_suggeres || '')
  .split(',')
  .map(r => r.trim())
  .filter(r => /^[A-Z][0-9]{4}$/.test(r));

// 5. Élargir avec passerelles si <= 2 ROME
let romesElargis = [...romesOriginaux];
if (romesOriginaux.length <= 2) {
  const seen = new Set(romesOriginaux);
  for (const rome of romesOriginaux) {
    for (const cible of (passerellesMap[rome] || [])) {
      if (!seen.has(cible) && /^[A-Z][0-9]{4}$/.test(cible)) {
        seen.add(cible);
        romesElargis.push(cible);
      }
    }
  }
}
romesElargis = romesElargis.slice(0, 6);
const romesStr = romesElargis.join(',');

// 6. Coordonnées
const dept = (j.departement || '75').trim();
const deptCoords = {
  '06':{lat:43.7102,lon:7.2620},'13':{lat:43.2965,lon:5.3698},
  '33':{lat:44.8378,lon:-0.5792},'34':{lat:43.6110,lon:3.8767},
  '35':{lat:48.1173,lon:-1.6778},'44':{lat:47.2184,lon:-1.5536},
  '59':{lat:50.6292,lon:3.0573},'69':{lat:45.7640,lon:4.8357},
  '75':{lat:48.8566,lon:2.3522},'77':{lat:48.5272,lon:2.6987},
  '78':{lat:48.8014,lon:2.1301},'89':{lat:47.7973,lon:3.5674},
  '91':{lat:48.6293,lon:2.4396},'92':{lat:48.8283,lon:2.2399},
  '93':{lat:48.9100,lon:2.4200},'94':{lat:48.7904,lon:2.4753},
  '95':{lat:49.0354,lon:2.0733}
};
const coords = deptCoords[dept] || deptCoords['75'];

// 7. Frein langue MNA
let frein_langue = false;
if (j.mna === true) {
  const nf = (j.niveau_francais_declare || '').toLowerCase();
  if (nf.includes('débutant') || nf.includes('debutant') || nf.includes('non francophone')) {
    frein_langue = true;
  }
}

// 8. URLs
const ft_url = `https://api.francetravail.io/partenaire/offresdemploi/v2/offres/search?departement=${dept}&distance=20&codeROME=${romesStr}&range=0-149`;
const lba_url = `https://api.apprentissage.beta.gouv.fr/api/job/v1/search?latitude=${coords.lat}&longitude=${coords.lon}&radius=25&romes=${romesStr}`;

return [{
  json: {
    jeune: {
      airtable_id: j.airtable_id,
      prenom: j.prenom,
      codes_rome_suggeres: j.codes_rome_suggeres,
      departement: j.departement,
      ville: j.ville,
      niveau_francais_declare: j.niveau_francais_declare,
      classe: j.classe,
      disponibilite: j.disponibilite,
      secteurs_interet: j.secteurs_interet || j.secteur_vise,
      besoins: j.besoins,
      attentes_mentor: j.attentes_mentor,
      mna: j.mna,
      secteur_vise: j.secteur_vise,
      skills_inferees: j.skills_inferees || '',
      frein_langue: frein_langue
    },
    romes_originaux: romesOriginaux,
    romes_elargis: romesElargis,
    nb_romes_originaux: romesOriginaux.length,
    nb_romes_elargis: romesElargis.length,
    elargissement_actif: romesOriginaux.length <= 2,
    token: token,
    ft_url: ft_url,
    lba_url: lba_url
  }
}];

// ============================================================================
// 🎯 SCORING v3 — Offres FT + Jobs LBA + Recruteurs LBA
// Compatible n8n Code node v2
// ============================================================================

const ftData = $('📡 Appel France Travail').first().json;
const lbaData = $('📡 Appel Bonne Alternance').first().json;
const jeuneData = $('⚙️ Construire requêtes').first().json;
const jeune = jeuneData.jeune;

const freinLangue = jeuneData.frein_langue || false;
const romesOriginaux = (jeune.codes_rome_suggeres || '').split(',').map(r => r.trim());
const romesElargis = jeuneData.romes_elargis || romesOriginaux;
const deptJeune = (jeune.departement || '').trim();
const dispo = (jeune.disponibilite || '').toLowerCase();
const attentes = (jeune.attentes_mentor || '').toLowerCase();
const besoinsStr = (jeune.besoins || '').toLowerCase();

const veutCDI = besoinsStr.includes('cdd') || besoinsStr.includes('cdi') || attentes.includes('cdi');
const veutAlternance = besoinsStr.includes('alternance') || dispo.includes('alternance');
const veutStage = besoinsStr.includes('stage') || dispo.includes('stage');
const dispoImmediate = dispo.includes('immédiate') || dispo.includes('immediate');
const dispoApres = dispo.includes('après') || dispo.includes('rentrée') || dispo.includes('septembre');

const motsCles = attentes.split(/[\s,;.!?]+/).filter(m => m.length > 4);

const PETITE_COURONNE = ['75','92','93','94'];
const IDF = ['75','92','93','94','77','78','91','95'];

// ============================================================================
// SCORING OFFRES (France Travail + LBA Jobs)
// ============================================================================

function scoreOffre(offre, source) {
  let score = 0;
  const detail = {};

  // 1. ROME (25 pts)
  const romeOffre = source === 'FT' ? (offre.romeCode || '') : '';
  if (source === 'FT') {
    if (romesOriginaux.includes(romeOffre)) { score += 25; detail.rome = 25; }
    else if (romesElargis.includes(romeOffre)) { score += 15; detail.rome = 15; }
    else { detail.rome = 0; }
  } else { score += 20; detail.rome = 20; }

  // 2. Débutant (20 pts)
  if (source === 'FT') {
    const deb = offre.experienceExige === 'D' || offre.experienceExige === 'S';
    if (deb) { score += 20; detail.debutant = 20; } else { detail.debutant = 0; }
  } else { score += 20; detail.debutant = 20; }

  // 3. Géo (15 pts)
  if (source === 'FT') {
    const deptOffre = (offre.lieuTravail?.codePostal || '').substring(0, 2);
    if (deptOffre === deptJeune) { score += 15; detail.geo = 15; }
    else if (PETITE_COURONNE.includes(deptOffre) && PETITE_COURONNE.includes(deptJeune)) { score += 10; detail.geo = 10; }
    else if (IDF.includes(deptOffre) && IDF.includes(deptJeune)) { score += 5; detail.geo = 5; }
    else { detail.geo = 0; }
  } else { score += 12; detail.geo = 12; }

  // 4. Langue (10 pts)
  if (freinLangue) {
    if (source === 'FT') {
      if ((offre.langues || []).length === 0) { score += 10; detail.langue = 10; } else { detail.langue = 0; }
    } else { score += 8; detail.langue = 8; }
  } else { score += 10; detail.langue = 10; }

  // 5. Permis (5 pts)
  if (source === 'FT') {
    if ((offre.permis || []).length === 0) { score += 5; detail.permis = 5; } else { detail.permis = 0; }
  } else { score += 5; detail.permis = 5; }

  // 6. Type contrat (10 / -10)
  if (source === 'FT') {
    const contrat = (offre.typeContratLibelle || offre.typeContrat || '').toLowerCase();
    const estInterim = contrat.includes('intérim') || contrat.includes('interim');
    const estCDI = contrat.includes('cdi');
    const estCDD = contrat.includes('cdd');
    if (veutCDI && estCDI) { score += 10; detail.contrat = 10; }
    else if (veutCDI && estCDD) { score += 3; detail.contrat = 3; }
    else if (veutCDI && estInterim) { score -= 10; detail.contrat = -10; }
    else if (veutAlternance && offre.alternance) { score += 10; detail.contrat = 10; }
    else if (veutStage) { score += 5; detail.contrat = 5; }
    else { detail.contrat = 0; }
  } else {
    if (veutAlternance) { score += 10; detail.contrat = 10; }
    else { score += 3; detail.contrat = 3; }
  }

  // 7. Sémantique (10 pts)
  const titreLC = (source === 'FT' ? (offre.intitule || '') : (offre.offer?.title || '')).toLowerCase();
  const matchMots = motsCles.filter(m => titreLC.includes(m));
  if (matchMots.length >= 2) { score += 10; detail.semantique = 10; }
  else if (matchMots.length === 1) { score += 5; detail.semantique = 5; }
  else { detail.semantique = 0; }

  // 8. Entreprise nommée (3 pts)
  const entreprise = source === 'FT' ? (offre.entreprise?.nom || '') : (offre.workplace?.name || '');
  if (entreprise && entreprise !== 'Non communiqué' && entreprise.length > 2) { score += 3; detail.entreprise_nommee = 3; }
  else { detail.entreprise_nommee = 0; }

  // 9. Temporalité (malus -15)
  if (dispoApres && !dispoImmediate && source === 'FT') {
    const c = (offre.typeContratLibelle || '').toLowerCase();
    if (c.includes('jour') || (c.includes('1 mois') && !c.includes('10')) || c.includes('5 jour')) {
      score -= 15; detail.temporalite = -15;
    } else { detail.temporalite = 0; }
  } else { detail.temporalite = 0; }

  return { score: Math.max(0, score), detail };
}

// ============================================================================
// SCORING RECRUTEURS LBA (marché caché)
// ============================================================================

function scoreRecruteur(r) {
  let score = 0;
  const detail = {};

  // Géo (30 pts)
  const deptR = (r.workplace?.location?.zipCode || '').substring(0, 2);
  if (deptR && deptR === deptJeune) { score += 30; detail.geo = 30; }
  else if (PETITE_COURONNE.includes(deptR) && PETITE_COURONNE.includes(deptJeune)) { score += 20; detail.geo = 20; }
  else if (IDF.includes(deptR) && IDF.includes(deptJeune)) { score += 12; detail.geo = 12; }
  else { detail.geo = 0; }

  // Taille PME (20 pts)
  const tailleScore = {'0-0':5,'1-2':10,'3-5':15,'6-9':20,'10-19':20,'20-49':18,'50-99':15,'100-199':12,'200-249':10,'250+':8};
  const pts = tailleScore[r.workplace?.size || ''] || 8;
  score += pts; detail.taille = pts;

  // OPCO (15 pts)
  const opco = r.workplace?.domain?.opco || '';
  if (opco && opco.length > 1) { score += 15; detail.opco = 15; } else { detail.opco = 0; }

  // Contact (15 pts)
  const phone = r.apply?.phone || '';
  const url = r.apply?.url || '';
  const rid = r.apply?.recipient_id || '';
  if (phone && phone.length >= 10) { score += 15; detail.contact = 15; }
  else if (url && url.startsWith('http')) { score += 10; detail.contact = 10; }
  else if (rid) { score += 8; detail.contact = 8; }
  else { detail.contact = 0; }

  // Nom (10 pts)
  const nom = r.workplace?.name || r.workplace?.legal_name || r.workplace?.brand || '';
  if (nom && nom.length > 2 && !nom.toLowerCase().includes('non communiqu')) { score += 10; detail.nom = 10; }
  else { detail.nom = 0; }

  // NAF (5 pts)
  if ((r.workplace?.domain?.naf?.code || '').length >= 2) { score += 5; detail.naf = 5; } else { detail.naf = 0; }

  // SIRET (5 pts)
  if ((r.workplace?.siret || '').length >= 14) { score += 5; detail.siret = 5; } else { detail.siret = 0; }

  return { score: Math.min(100, Math.max(0, score)), detail };
}

// ============================================================================
// SCORER TOUT
// ============================================================================

const offresFT = (ftData.resultats || []).map(o => {
  const { score, detail } = scoreOffre(o, 'FT');
  return {
    source: 'France Travail', offre_id: o.id, titre: o.intitule,
    entreprise: o.entreprise?.nom || 'Non communiqué',
    lieu: o.lieuTravail?.libelle || '',
    departement_offre: (o.lieuTravail?.codePostal || '').substring(0, 2),
    type_contrat: o.typeContratLibelle || o.typeContrat || '',
    est_alternance: o.alternance === true,
    debutant_accepte: o.experienceExige === 'D',
    url_offre: o.origineOffre?.urlOrigine || `https://candidat.francetravail.fr/offres/recherche/detail/${o.id}`,
    score, score_detail: detail
  };
});

const jobsLBA = (lbaData.jobs || []).map(j => {
  const { score, detail } = scoreOffre(j, 'LBA');
  return {
    source: 'La Bonne Alternance', offre_id: j.identifier?.partner_job_id || j.identifier?.id || '',
    titre: j.offer?.title || '', entreprise: j.workplace?.name || 'Non communiqué',
    lieu: j.workplace?.location?.city || '', departement_offre: '',
    type_contrat: (j.contract?.type || []).join(', '),
    est_alternance: true, debutant_accepte: true,
    url_offre: j.apply?.url || '', score, score_detail: detail
  };
});

const recruteursLBA = (lbaData.recruiters || []).map(r => {
  const { score, detail } = scoreRecruteur(r);
  return {
    source: 'LBA Recruteur', offre_id: r.identifier?.id || '',
    titre: `Candidature spontanée - ${r.workplace?.domain?.naf?.label || r.workplace?.name || 'Entreprise'}`,
    entreprise: r.workplace?.name || r.workplace?.legal_name || 'Non communiqué',
    lieu: r.workplace?.location?.city || '',
    departement_offre: (r.workplace?.location?.zipCode || '').substring(0, 2),
    type_contrat: 'Alternance (spontanée)', est_alternance: true, debutant_accepte: true,
    url_offre: r.apply?.url || '', score, score_detail: detail,
    telephone: r.apply?.phone || '', opco: r.workplace?.domain?.opco || ''
  };
});

// Prioriser ROME originaux avant passerelles
const allOffres = [...offresFT, ...jobsLBA].filter(o => o.score >= 55 && o.offre_id);
const offresRomeOriginal = allOffres.filter(o => o.score_detail.rome >= 20).sort((a, b) => b.score - a.score);
const offresPasserelle = allOffres.filter(o => o.score_detail.rome < 20).sort((a, b) => b.score - a.score);
// D'abord les ROME originaux (jusqu'à 7), puis compléter avec passerelles
const topOffres = [...offresRomeOriginal.slice(0, 7), ...offresPasserelle.slice(0, 10 - Math.min(offresRomeOriginal.length, 7))].slice(0, 10);
const topRecruteurs = recruteursLBA.filter(r => r.score >= 40 && r.offre_id).sort((a, b) => b.score - a.score).slice(0, 5);

return [{ json: {
  jeune, offres: topOffres, recruteurs: topRecruteurs,
  debug: { nb_ft: (ftData.resultats || []).length, nb_lba_jobs: (lbaData.jobs || []).length, nb_lba_recruteurs: (lbaData.recruiters || []).length, nb_offres_apres_score: topOffres.length, nb_recruteurs_apres_score: topRecruteurs.length }
}}];

// ============================================================================
// 📝 PREPARER PROMPT IA — n8n Code node v2
// ============================================================================

const data = $input.first().json;
const jeune = data.jeune;
const offres = data.offres;
const recruteurs = data.recruteurs;
const debug = data.debug;

if (offres.length === 0 && recruteurs.length === 0) {
  return [{ json: { skip: true, jeune_prenom: jeune.prenom, queries: [] } }];
}

const offresList = offres.map((o, i) =>
  `${i+1}. [${o.source}] ${o.titre} | ${o.entreprise} | ${o.lieu} | ${o.type_contrat} | Score: ${o.score}`
).join('\n');

const recruteursList = recruteurs.map((r, i) =>
  `${i+1}. ${r.entreprise} | ${r.lieu} | ${r.opco || 'OPCO inconnu'} | ${r.telephone || 'Pas de tel'} | Score: ${r.score}`
).join('\n');

const prompt = `Tu es un conseiller insertion spécialisé jeunes vulnérables (ASE/MNA). Analyse ce matching et sélectionne les meilleures opportunités.

PROFIL DU JEUNE :
- Prénom : ${jeune.prenom}
- Classe : ${jeune.classe || 'Non précisé'}
- Français : ${jeune.niveau_francais_declare || 'Non précisé'}
- MNA : ${jeune.mna ? 'Oui' : 'Non'}
- Secteur visé : ${jeune.secteurs_interet}
- Disponibilité : ${jeune.disponibilite}
- Besoins : ${jeune.besoins}
- Skills inférées : ${jeune.skills_inferees || 'Aucune'}
- Ce qu'il/elle dit : "${(jeune.attentes_mentor || '').substring(0, 500)}"

OFFRES D'EMPLOI (${debug.nb_ft} FT + ${debug.nb_lba_jobs} LBA, top ${offres.length} après scoring) :
${offresList || 'Aucune offre'}

RECRUTEURS MARCHÉ CACHÉ (${debug.nb_lba_recruteurs} identifiés, top ${recruteurs.length} après scoring) :
${recruteursList || 'Aucun recruteur'}

RÈGLES :
- Sélectionne max 3 offres et max 2 recruteurs (ou moins si peu pertinents)
- Élimine les incohérences (intérim 5j pour quelqu'un qui veut un CDI, offre trop en dessous du niveau, etc.)
- Pour chaque sélection, écris un message court et motivant en tutoiement pour le jeune (1 phrase)
- Pour les recruteurs, explique pourquoi une candidature spontanée a du sens

Réponds UNIQUEMENT en JSON valide, sans markdown :
{"offres":[{"rang":1,"message":"...","raison":"..."}],"recruteurs":[{"rang":1,"message":"...","raison":"..."}]}`;

return [{ json: { prompt, jeune, offres, recruteurs, debug } }];

// Vérifier si le profil a été chargé
const debugInput = $('🔧 Parser input').first().json;
if (!debugInput.has_id) {
  return [{ json: { response: 'Erreur: impossible d\'identifier le jeune. Input reçu: ' + debugInput.debug_raw_input } }];
}

// Formater les résultats pour retour à l'agent Koda
const aiResponse = $('🧠 Review IA (Haiku)').first().json;
const data = $('📝 Préparer prompt IA').first().json;
const jeune = data.jeune;
const offres = data.offres;
const recruteurs = data.recruteurs;

let selectionsOffres = [];
let selectionsRecruteurs = [];
try {
  const aiText = aiResponse.content?.[0]?.text || '{"offres":[],"recruteurs":[]}';
  const cleaned = aiText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const parsed = JSON.parse(cleaned);
  selectionsOffres = parsed.offres || [];
  selectionsRecruteurs = parsed.recruteurs || [];
} catch(e) {
  selectionsOffres = offres.slice(0, 3).map((o, i) => ({ rang: i + 1, message: 'Bonne opportunité', raison: 'Score élevé' }));
  selectionsRecruteurs = recruteurs.slice(0, 2).map((r, i) => ({ rang: i + 1, message: 'Entreprise qui recrute', raison: 'Score élevé' }));
}

let result = `RÉSULTATS (${data.debug.nb_ft} offres FT, ${data.debug.nb_lba_jobs} alternances, ${data.debug.nb_lba_recruteurs} recruteurs analysés)\n\n`;

if (selectionsOffres.length > 0) {
  result += 'OFFRES SÉLECTIONNÉES :\n';
  selectionsOffres.forEach(sel => {
    const o = offres[sel.rang - 1];
    if (!o) return;
    result += `${sel.rang}. ${o.titre} | ${o.entreprise} | ${o.lieu} | ${o.type_contrat} | Score: ${o.score}\n`;
    result += `   Lien: ${o.url_offre}\n`;
    result += `   "${sel.message}"\n\n`;
  });
}

if (selectionsRecruteurs.length > 0) {
  result += 'RECRUTEURS (candidature spontanée) :\n';
  selectionsRecruteurs.forEach(sel => {
    const r = recruteurs[sel.rang - 1];
    if (!r) return;
    result += `${sel.rang}. ${r.entreprise} | ${r.lieu}`;
    if (r.telephone) result += ` | Tel: ${r.telephone}`;
    result += `\n   Lien: ${r.url_offre}\n`;
    result += `   "${sel.message}"\n\n`;
  });
}

if (selectionsOffres.length === 0 && selectionsRecruteurs.length === 0) {
  result += 'Aucune offre pertinente trouvée. Suggère au jeune d\'élargir ses critères.';
} else {
  result += 'Présente ces résultats au jeune de manière naturelle. Inclus les liens.';
}

return [{ json: { response: result } }];

// ============================================================
// 🔧 Parser l'input du toolWorkflow
// Le format varie selon la version n8n / type d'appel :
//   - $json.query (toolWorkflow standard)
//   - $json.chatInput (certaines versions)
//   - $json.airtable_id (si passé via fields)
//   - $json (peut être un string directement)
//   - $json.input (autre format possible)
// On essaie TOUT et on log pour debug
// ============================================================

const raw = $input.first().json;

// Log complet pour debug
const rawStr = JSON.stringify(raw).substring(0, 500);

// Essayer d'extraire l'airtable_id de toutes les sources possibles
let airtableId = '';

// Source 1: champs standards toolWorkflow
if (raw.query && typeof raw.query === 'string') airtableId = raw.query.trim();
else if (raw.chatInput && typeof raw.chatInput === 'string') airtableId = raw.chatInput.trim();
else if (raw.airtable_id && typeof raw.airtable_id === 'string') airtableId = raw.airtable_id.trim();
else if (raw.input && typeof raw.input === 'string') airtableId = raw.input.trim();
// Source 2: peut-être un objet avec des sous-champs
else if (raw.query?.query) airtableId = raw.query.query.trim();
else if (raw.action_input) airtableId = raw.action_input.trim();
// Source 3: parcourir toutes les clés à la recherche d'un truc qui ressemble à un airtable_id
else {
  for (const [k, v] of Object.entries(raw)) {
    if (typeof v === 'string' && (v.startsWith('rec') || v.startsWith('TEST_'))) {
      airtableId = v.trim();
      break;
    }
  }
}

// Nettoyer : l'agent peut envoyer du texte autour de l'ID
// ex: "Searching for TEST_MOURAD_001" → extraire TEST_MOURAD_001 ou recXXXXXXX
const idMatch = airtableId.match(/(rec[A-Za-z0-9]+|TEST_[A-Za-z0-9_]+)/);
if (idMatch) airtableId = idMatch[1];

return [{
